int main(void) {
    unsigned int a = 0b1010;  /* 10 in decimal */
    unsigned int b = 0b1100;  /* 12 in decimal */

    printf("a & b  = %u\n", a & b);   /* 8  (1000) */
    printf("a | b  = %u\n", a | b);   /* 14 (1110) */
    printf("a ^ b  = %u\n", a ^ b);   /* 6  (0110) */
    printf("~a     = %u\n", ~a);      /* 4294967285 (all bits flipped) */
    printf("a << 2 = %u\n", a << 2);  /* 40 (101000) -- multiply by 4 */
    printf("b >> 2 = %u\n", b >> 2);  /* 3  (0011)   -- divide by 4 */

    /* XOR properties */
    printf("\nXOR properties:\n");
    printf("a ^ 0 = %u\n", a ^ 0);    /* a (identity) */
    printf("a ^ a = %u\n", a ^ a);    /* 0 (self-inverse) */
    printf("a ^ b ^ b = %u\n", a ^ b ^ b);  /* a (cancellation) */

    /* NOT on signed integer */
    int x = 5;
    printf("\n~5 = %d\n", ~x);  /* -6 (two's complement: ~x = -(x+1)) */

    /* Left shift = multiply by power of 2 */
    printf("3 << 4 = %d\n", 3 << 4);  /* 48 = 3 * 16 */

    /* Right shift = divide by power of 2 */
    printf("48 >> 3 = %d\n", 48 >> 3);  /* 6 = 48 / 8 */

    return 0;
}

