#include <stdio.h>

/* Brian Kernighan's algorithm: O(number of set bits) */
int countSetBits(unsigned int n) {
    int count = 0;
    while (n) {
        n = n & (n - 1);  /* clear lowest set bit */
        count++;
    }
    return count;
}

/* Naive approach: O(number of total bits) */
int countSetBitsNaive(unsigned int n) {
    int count = 0;
    while (n) {
        count += n & 1;
        n >>= 1;
    }
    return count;
}

/* Lookup table approach: O(1) with precomputation */
int table[256];  /* for 8-bit chunks */

void buildTable(void) {
    table[0] = 0;
    for (int i = 1; i < 256; i++)
        table[i] = (i & 1) + table[i >> 1];
}

int countSetBitsTable(unsigned int n) {
    return table[n & 0xFF] + table[(n >> 8) & 0xFF] +
           table[(n >> 16) & 0xFF] + table[(n >> 24) & 0xFF];
}

int main(void) {
    buildTable();

    unsigned int values[] = {0, 1, 7, 15, 255, 1023, 0xFFFFFFFF};
    int n = sizeof(values) / sizeof(values[0]);

    for (int i = 0; i < n; i++) {
        printf("%10u: Kernighan=%d, Naive=%d, Table=%d\n",
               values[i],
               countSetBits(values[i]),
               countSetBitsNaive(values[i]),
               countSetBitsTable(values[i]));
    }
    /* 0: 0, 1: 1, 7: 3, 15: 4, 255: 8, 1023: 10, 4294967295: 32 */

    /* GCC/Clang built-in */
    printf("\n__builtin_popcount(255) = %d\n", __builtin_popcount(255));  /* 8 */

    return 0;
}

int countSetBits(unsigned int n) {
    int count = 0;
    while (n) {
        n &= (n - 1);  /* clear lowest set bit */
        count++;
    }
    return count;
}
