#include <stdio.h>

/* XOR swap */
void xorSwap(int *a, int *b) {
    if (a == b) return;  /* CRITICAL: avoid self-swap */
    *a ^= *b;
    *b ^= *a;
    *a ^= *b;
}

/* Arithmetic swap */
void arithmeticSwap(int *a, int *b) {
    *a = *a + *b;
    *b = *a - *b;
    *a = *a - *b;
}

/* Standard swap (use this in practice) */
void standardSwap(int *a, int *b) {
    int temp = *a;
    *a = *b;
    *b = temp;
}

int main(void) {
    int x = 5, y = 10;
    printf("Before: x=%d, y=%d\n", x, y);

    xorSwap(&x, &y);
    printf("After XOR swap: x=%d, y=%d\n", x, y);  /* x=10, y=5 */

    arithmeticSwap(&x, &y);
    printf("After arith swap: x=%d, y=%d\n", x, y);  /* x=5, y=10 */

    /* Demonstrate the self-swap bug */
    int z = 42;
    /* xorSwap(&z, &z); would give z=0 without the guard */
    xorSwap(&z, &z);  /* safe: guard returns early */
    printf("Self-swap guarded: z=%d\n", z);  /* 42 */

    return 0;
}

void xorSwap(int *a, int *b) {
    if (a == b) return;  /* guard! */
    *a ^= *b;
