/* Find the single non-repeating element: O(n) time, O(1) space */
int findUnique(int arr[], int n) {
    int result = 0;
    for (int i = 0; i < n; i++)
        result ^= arr[i];
    return result;
}

/* Variant: find TWO non-repeating elements */
void findTwoUnique(int arr[], int n, int *x, int *y) {
    int xorAll = 0;
    for (int i = 0; i < n; i++)
        xorAll ^= arr[i];
    /* xorAll = a ^ b. Find any set bit to split into groups. */

    int diffBit = xorAll & (-xorAll);  /* isolate lowest set bit */

    *x = 0;
    *y = 0;
    for (int i = 0; i < n; i++) {
        if (arr[i] & diffBit)
            *x ^= arr[i];
        else
            *y ^= arr[i];
    }
}

int main(void) {
    /* Single unique element */
    int arr1[] = {2, 3, 5, 4, 5, 3, 4};
    printf("Unique: %d\n", findUnique(arr1, 7));  /* 2 */

    int arr2[] = {7, 3, 5, 3, 5};
    printf("Unique: %d\n", findUnique(arr2, 5));  /* 7 */

    /* Two unique elements */
    int arr3[] = {1, 2, 3, 2, 1, 4};
    int a, b;
    findTwoUnique(arr3, 6, &a, &b);
    printf("Two unique: %d and %d\n", a, b);  /* 3 and 4 (or 4 and 3) */

    return 0;
}

