unsigned int insertField(unsigned int value, int offset, int width,
                         unsigned int field_val) {
    unsigned int mask = ((1U << width) - 1) << offset;
    value &= ~mask;                      /* clear field */
    value |= (field_val << offset) & mask;  /* insert new value */
    return value;
