/* Simple loop: O(32) */
uint32_t reverseBits(uint32_t n) {
    uint32_t result = 0;
    for (int i = 0; i < 32; i++) {
        result <<= 1;
        result |= (n & 1);
        n >>= 1;
    }
    return result;
}

/* Divide and conquer: O(log 32) = O(5) steps */
uint32_t reverseBitsFast(uint32_t n) {
    n = ((n & 0x55555555) << 1)  | ((n >> 1)  & 0x55555555);
    n = ((n & 0x33333333) << 2)  | ((n >> 2)  & 0x33333333);
    n = ((n & 0x0F0F0F0F) << 4)  | ((n >> 4)  & 0x0F0F0F0F);
    n = ((n & 0x00FF00FF) << 8)  | ((n >> 8)  & 0x00FF00FF);
    n = (n << 16) | (n >> 16);
    return n;
}

void printBinary32(uint32_t n) {
    for (int i = 31; i >= 0; i--)
        printf("%d", (n >> i) & 1);
    printf("\n");
}

int main(void) {
    uint32_t num = 43261596;  /* 00000010100101000001111010011100 */
    printf("Original: "); printBinary32(num);

    uint32_t rev = reverseBits(num);
    printf("Reversed: "); printBinary32(rev);
    /* 00111001011110000010100101000000 = 964176192 */
    printf("Result: %u\n", rev);  /* 964176192 */

    uint32_t rev2 = reverseBitsFast(num);
    printf("Fast:   %u\n", rev2);  /* 964176192 (same) */

    return 0;
}

