/* Find position (0-indexed) of rightmost set bit */
int rightmostSetBitPos(int n) {
    if (n == 0) return -1;  /* no set bits */

    int pos = 0;
    int rsb = n & (-n);  /* isolate RSB */
    while (rsb > 1) {
        rsb >>= 1;
        pos++;
    }
    return pos;
}

