/* Detect endianness at runtime */
int isLittleEndian(void) {
    unsigned int x = 1;
    return *((unsigned char *)&x) == 1;
}

/* Manual byte swap (endian conversion) for 32-bit */
uint32_t swapEndian32(uint32_t n) {
    return ((n >> 24) & 0x000000FF) |
           ((n >> 8)  & 0x0000FF00) |
           ((n << 8)  & 0x00FF0000) |
           ((n << 24) & 0xFF000000);
}

/* Manual byte swap for 16-bit */
uint16_t swapEndian16(uint16_t n) {
    return (n >> 8) | (n << 8);
}

int main(void) {
    printf("This system is %s-endian\n",
           isLittleEndian() ? "little" : "big");

    uint32_t val = 0x12345678;

    /* Show bytes in memory order */
    unsigned char *bytes = (unsigned char *)&val;
    printf("\n0x%X in memory: ", val);
    for (int i = 0; i < 4; i++)
        printf("%02X ", bytes[i]);
    printf("\n");  /* Little-endian: 78 56 34 12 */

    /* Byte swap */
    uint32_t swapped = swapEndian32(val);
    printf("Swapped: 0x%X\n", swapped);  /* 0x78563412 */

    /* Network byte order conversion */
    uint32_t net = htonl(val);  /* host to network */
    printf("htonl(0x12345678) = 0x%X\n", net);
    /* On little-endian: 0x78563412; on big-endian: 0x12345678 */

    uint32_t host = ntohl(net);  /* network to host */
    printf("ntohl back: 0x%X\n", host);  /* 0x12345678 */

    return 0;
}

