#include <stdio.h>

/* Define flags as powers of 2 */
#define PERM_READ    (1 << 0)  /* 0x01 = 001 */
#define PERM_WRITE   (1 << 1)  /* 0x02 = 010 */
#define PERM_EXEC    (1 << 2)  /* 0x04 = 100 */
#define PERM_ALL     (PERM_READ | PERM_WRITE | PERM_EXEC)  /* 0x07 */

/* Using enum for type safety */
typedef enum {
    OPT_VERBOSE  = 1 << 0,
    OPT_DEBUG    = 1 << 1,
    OPT_COLOR    = 1 << 2,
    OPT_LOGFILE  = 1 << 3,
    OPT_DAEMON   = 1 << 4,
} Options;

void printPerms(int perms) {
    printf("%c%c%c",
           (perms & PERM_READ)  ? 'r' : '-',
           (perms & PERM_WRITE) ? 'w' : '-',
           (perms & PERM_EXEC)  ? 'x' : '-');
}

void processOptions(unsigned int opts) {
    if (opts & OPT_VERBOSE) printf("Verbose mode\n");
    if (opts & OPT_DEBUG)   printf("Debug mode\n");
    if (opts & OPT_COLOR)   printf("Color enabled\n");
    if (opts & OPT_LOGFILE) printf("Logging to file\n");
    if (opts & OPT_DAEMON)  printf("Running as daemon\n");
}

int main(void) {
    /* Permission flags */
    int perms = PERM_READ | PERM_WRITE;  /* rw- */
    printf("Permissions: "); printPerms(perms); printf("\n");  /* rw- */

    /* Add execute permission */
    perms |= PERM_EXEC;
    printf("After +exec: "); printPerms(perms); printf("\n");  /* rwx */

    /* Remove write permission */
    perms &= ~PERM_WRITE;
    printf("After -write: "); printPerms(perms); printf("\n");  /* r-x */

    /* Toggle execute */
    perms ^= PERM_EXEC;
    printf("Toggle exec: "); printPerms(perms); printf("\n");  /* r-- */

    /* Check specific permission */
    if (perms & PERM_READ)
        printf("Has read permission\n");

    /* Option flags */
    printf("\n");
    unsigned int opts = OPT_VERBOSE | OPT_COLOR | OPT_DAEMON;
    processOptions(opts);

    return 0;
}

