#include <limits.h>

/* Branchless absolute value */
int branchlessAbs(int n) {
    int mask = n >> 31;  /* 0 if positive, -1 if negative */
    return (n ^ mask) - mask;
}

/* Alternative formulation */
int branchlessAbs2(int n) {
    int mask = n >> 31;
    return (n + mask) ^ mask;
}

/* Traditional with branch */
int traditionalAbs(int n) {
    return (n < 0) ? -n : n;
}

int main(void) {
    int tests[] = {0, 5, -5, 42, -42, 100, -100, INT_MAX};
    int n = sizeof(tests) / sizeof(tests[0]);

    for (int i = 0; i < n; i++) {
        printf("abs(%d) = %d (branchless), %d (v2)\n",
               tests[i],
               branchlessAbs(tests[i]),
               branchlessAbs2(tests[i]));
    }

    /* WARNING: INT_MIN overflow */
    printf("\nabs(INT_MIN) = %d (OVERFLOW!)\n", branchlessAbs(INT_MIN));
    /* Result is still INT_MIN (undefined behavior technically) */

    return 0;
}

