int main(void) {
    /* 1. Even/Odd check */
    printf("7 is %s\n", (7 & 1) ? "odd" : "even");  /* odd */
    printf("8 is %s\n", (8 & 1) ? "odd" : "even");  /* even */

    /* 2. Multiply and divide by powers of 2 */
    printf("5 * 8 = %d\n", 5 << 3);    /* 40 */
    printf("40 / 4 = %d\n", 40 >> 2);  /* 10 */

    /* 3. Turn off rightmost set bit */
    printf("12 & 11 = %d\n", 12 & 11);  /* 8: 1100 & 1011 = 1000 */

    /* 4. Check opposite signs */
    int a = -5, b = 10;
    printf("%d and %d opposite signs: %s\n", a, b,
           ((a ^ b) < 0) ? "yes" : "no");  /* yes */

    /* 5. Case conversion (ASCII) */
    char upper = 'A';
    char lower = upper | 0x20;   /* 'a' */
    char back  = lower & ~0x20;  /* 'A' */
    char toggled = upper ^ 0x20; /* 'a' */
    printf("'%c' -> '%c' -> '%c', toggle: '%c'\n",
           upper, lower, back, toggled);

    /* 6. Branchless min/max */
    int x = 7, y = 3;
    int min_val = y ^ ((x ^ y) & -(x < y));
    int max_val = x ^ ((x ^ y) & -(x < y));
    printf("min(%d,%d) = %d, max = %d\n", x, y, min_val, max_val);
    /* min=3, max=7 */

    /* 7. Count leading zeros to find log2 */
    unsigned int v = 16;
    int log2 = 31 - __builtin_clz(v);
    printf("log2(%u) = %d\n", v, log2);  /* 4 */

    /* 8. Round up to next power of 2 */
    unsigned int num = 13;
    num--;
    num |= num >> 1;
    num |= num >> 2;
    num |= num >> 4;
    num |= num >> 8;
    num |= num >> 16;
    num++;
    printf("Next power of 2 after 13: %u\n", num);  /* 16 */

    /* 9. Average without overflow */
    int p = 100, q = 200;
    int avg = (p & q) + ((p ^ q) >> 1);
    printf("avg(%d, %d) = %d\n", p, q, avg);  /* 150 */

    return 0;
}

